// // If zx is 01, then j is 0.
// If zx is 00, then j is 0.
// If zx is 11, then j is 1.
// If zx is 10, then j is 0.
module top_module (
    input z,
    input x,
    output reg j
);
    always @(*) begin
        case ({z, x})
            2'b01: j = 1'b1;
            2'b00: j = 1'b1;
            2'b11: j = 1'b0;
            2'b10: j = 1'b1;
        endcase
    end
endmodule

